      <script>
        (function() {
          const countdownElement = document.getElementById('countdown-27438-27438-1378742741');
          const badgeContainer = document.getElementById('badge-container-27438-27438-1378742741');
          const endTime = 1771056000;
          
          function updateCountdown() {
            const now = Math.floor(Date.now() / 1000);
            const remaining = endTime - now;
            
            if (remaining <= 0) {
              if (countdownElement) {
                countdownElement.textContent = '';
              }
              // 移除整个倒计时容器（如果不需要显示过期内容）
              if (badgeContainer) {
                badgeContainer.style.display = 'none';
              }
              return;
            }
            
            const days = Math.floor(remaining / 86400);
            const hours = Math.floor((remaining % 86400) / 3600).toString().padStart(2, '0');
            const minutes = Math.floor((remaining % 3600) / 60).toString().padStart(2, '0');
            const seconds = (remaining % 60).toString().padStart(2, '0');
            const dataname = 'días';
            if(countdownElement) {
              if (days > 0) {
                countdownElement.textContent = days + dataname +' ' + hours + ':' + minutes + ':' + seconds;
              } else if (hours > 0) {
                countdownElement.textContent = hours + ':' + minutes + ':' + seconds;
              } else {
                countdownElement.textContent = minutes + ':' + seconds;
              }
            }
          }
          
          // 初始更新
          updateCountdown();
          
          // 每秒更新一次
          const countdownInterval = setInterval(updateCountdown, 1000);
        })();
      </script>
    
